from collections import defaultdict
import statistics

def aggregate_unit_economics(records: list[dict]) -> dict:
    """
    Aggregate per-conversation records into unit economic metrics.
    records: list of ConversationTracker.summary() dicts
    """
    if not records:
        return {}

    total_cost = sum(r["cost_usd"] for r in records)
    total_calls = sum(r["api_calls"] for r in records)
    n_conversations = len(records)

    costs = [r["cost_usd"] for r in records]
    calls_per_conv = [r["api_calls"] for r in records]

    # By feature breakdown
    by_feature = defaultdict(list)
    for r in records:
        by_feature[r["feature"]].append(r)

    feature_metrics = {}
    for feat, feat_records in by_feature.items():
        feat_cost = sum(r["cost_usd"] for r in feat_records)
        feature_metrics[feat] = {
            "conversations": len(feat_records),
            "total_cost_usd": round(feat_cost, 4),
            "avg_cost_per_conv": round(feat_cost / len(feat_records), 6),
            "cost_share_pct": round(feat_cost / total_cost * 100, 1),
        }

    return {
        "n_conversations": n_conversations,
        "total_cost_usd": round(total_cost, 4),
        "cost_per_conversation": {
            "mean":   round(statistics.mean(costs), 6),
            "median": round(statistics.median(costs), 6),
            "p75":    round(sorted(costs)[int(len(costs) * 0.75)], 6),
            "p95":    round(sorted(costs)[int(len(costs) * 0.95)], 6),
        },
        "cost_per_api_call": round(total_cost / total_calls, 6) if total_calls else 0,
        "avg_calls_per_conversation": round(statistics.mean(calls_per_conv), 2),
        "by_feature": feature_metrics,
    }

