UNIT_COST_TARGETS = {
    # (warn_threshold, critical_threshold) in USD
    "support_bot":        (0.12, 0.20),
    "code_review":        (0.22, 0.40),
    "doc_summarization":  (0.60, 1.00),
    "agentic_task":       (1.20, 2.50),
}

def check_unit_cost(feature: str, actual_cost: float) -> str:
    if feature not in UNIT_COST_TARGETS:
        return "untracked"
    warn, crit = UNIT_COST_TARGETS[feature]
    if actual_cost >= crit:
        return f"CRITICAL: ${actual_cost:.4f} exceeds ${crit:.2f} threshold for {feature}"
    if actual_cost >= warn:
        return f"WARNING: ${actual_cost:.4f} approaching ${warn:.2f} warn threshold for {feature}"
    return "ok"

from dataclasses import dataclass

@dataclass
class OutlierConversation:
    conversation_id: str
    feature: str
    cost_usd: float
    api_calls: int
    total_tokens: int

def detect_outlier_conversations(
    records: list[dict],
    cost_p95_threshold: float,
    min_calls_threshold: int = 30,
) -> list[OutlierConversation]:
    """
    Flag conversations that are in the P95+ cost tier OR have
    an abnormally high call count (possible loop).
    """
    outliers = []
    for r in records:
        is_expensive = r["cost_usd"] >= cost_p95_threshold
        is_looping   = r["api_calls"] >= min_calls_threshold
        if is_expensive or is_looping:
            outliers.append(OutlierConversation(
                conversation_id=r["conversation_id"],
                feature=r["feature"],
                cost_usd=r["cost_usd"],
                api_calls=r["api_calls"],
                total_tokens=r["input_tokens"] + r["output_tokens"],
            ))
    return sorted(outliers, key=lambda o: o.cost_usd, reverse=True)


def summarize_outlier_impact(
    outliers: list[OutlierConversation],
    total_cost_usd: float,
) -> dict:
    outlier_cost = sum(o.cost_usd for o in outliers)
    return {
        "outlier_count": len(outliers),
        "outlier_cost_usd": round(outlier_cost, 2),
        "outlier_share_pct": round(outlier_cost / total_cost_usd * 100, 1) if total_cost_usd else 0,
        "top_5": [
            {"id": o.conversation_id, "cost": o.cost_usd, "calls": o.api_calls}
            for o in outliers[:5]
        ],
    }

COST_ALLOCATION_TAGS = {
    # tag -> (allocation_type, target_feature_or_cost_center)
    "support_bot":       ("direct",     "customer-support"),
    "code_review":       ("direct",     "developer-tools"),
    "nightly_index":     ("batch",      "search-platform"),
    "health_check":      ("overhead",   "platform"),
    "eval_harness":      ("overhead",   "platform"),
}

def allocate_cost(tag: str, cost_usd: float) -> dict:
    alloc_type, target = COST_ALLOCATION_TAGS.get(tag, ("overhead", "platform"))
    return {"tag": tag, "type": alloc_type, "target": target, "cost_usd": cost_usd}
